<template>
  <div class="blocModale" v-if="show">
    <div class="overlay" v-on:click="toggleModale"></div>

    <div class="modale">
      <div class="header">
        <h2>Reven</h2>
        <div class="close-container" v-on:click="toggleModale">
          <div class="leftright"></div>
          <div class="rightleft"></div>
        </div>
      </div>
      <div class="main">
        <div></div>
      </div>
    </div>
  </div>
</template>

<script>
export default {
  name: 'RevenModale',
  props: ['show', 'toggleModale']
}
</script>

<style lang="scss" scoped>
    .blocModale{
      z-index: 10;
      position: fixed;
      top: 0;
      left: 0;
      bottom: 0;
      right: 0;
      display: flex;
      justify-content: center;
      align-items: center;
      flex-direction: column;
      width: 80%;
      height: 80%;
      margin: auto;
    }

    .overlay{
      background: rgba(0,0,0,0.5);
      position: fixed;
      top: 0;
      left: 0;
      bottom: 0;
      right: 0;
    }

    .modale {
      height: 100%;
      width: 100%;
      background: #f1f1f1;
      color: #333;
      z-index: 10;
      top: 10%;
      border-radius: 1.2vw;
    }

    .header{
      background: #6a4b3c;
      width: 100%;
      height: 6%;
      border-radius: 1vw 1vw 0 0;
    }

    .main{
      background: #f1f1f1;
      width: 100%;
      height: 94%;
      border-radius: 0 0 1vw 1vw;
    }

    // COLORS
    $softorange: #F4A259;
    $tomatored: #F25C66;
    $mediumblu: #1E272D;

    .close-container{
      position: absolute;
      top: 5px;
      right: 30px;
      height: 50px;
      width: 50px;
      cursor: pointer;
    }

    .leftright{
      height: 4px;
      width: 50px;
      position: absolute;
      margin-top: 24px;
      background-color: $softorange;
      border-radius: 2px;
      transform: rotate(45deg);
      transition: all .3s ease-in;
    }

    .rightleft{
      height: 4px;
      width: 50px;
      position: absolute;
      margin-top: 24px;
      background-color: $softorange;
      border-radius: 2px;
      transform: rotate(-45deg);
      transition: all .3s ease-in;
    }


    .close-container:hover .leftright{
      transform: rotate(-45deg);
      background-color: $tomatored;
    }
    .close-container:hover .rightleft{
      transform: rotate(45deg);
      background-color: $tomatored;
    }
    .close-container:hover label{
      opacity: 1;
    }

    h2 {
      text-align: center;
      margin: 0;
      color: #f1f1f1;
      height: 100%;
      font-size: 2vw;
    }
</style>